import * as React from 'react';
import { SimpleBarScrollArea_unstable as SimpleBarScrollArea } from './SimpleBarScrollArea';
import NativeScrollArea from './NativeScrollArea';
import type {
  VirtualScrollAreaProps,
  NativeScrollAreaProps,
  ScrollAreaProps,
  SharedScrollAreaProps,
} from './interface';

export const ScrollArea = React.forwardRef<HTMLDivElement, ScrollAreaProps>(
  ({ virtual = false, ...restProps }, ref) => {
    if (virtual) {
      return <SimpleBarScrollArea ref={ref} {...restProps} />;
    }
    return <NativeScrollArea ref={ref} {...restProps} />;
  },
);

export type { ScrollAreaProps, NativeScrollAreaProps, VirtualScrollAreaProps, SharedScrollAreaProps };
